import type { LessonContent } from "./types";

export const neurologyLessons: Record<string, LessonContent> = {
  "ischemic-stroke": {
    title: "Ischemic Stroke",
    cellular: { title: "Cerebral Artery Occlusion", content: "Ischemic stroke occurs when a cerebral artery is occluded by a thrombus or embolus, depriving brain tissue of oxygen and glucose. The ischemic core suffers irreversible necrosis within minutes, while the surrounding penumbra is salvageable with rapid reperfusion. Excitotoxicity from glutamate release, calcium influx, free radical production, and inflammatory cascades extend infarction into the penumbra over hours. Thrombotic strokes typically result from atherosclerotic plaque rupture in large cerebral arteries, while embolic strokes originate from cardiac sources (atrial fibrillation, valvular disease) or carotid atherosclerosis." },
    riskFactors: ["Atrial fibrillation - single greatest risk for embolic stroke", "Hypertension - most important modifiable risk factor", "Diabetes mellitus accelerating atherosclerosis", "Hyperlipidemia contributing to atherosclerotic plaque formation", "Smoking causing endothelial injury and hypercoagulability", "Carotid artery stenosis greater than 70%", "Previous TIA - warning sign of impending stroke", "Sickle cell disease in younger patients"],
    diagnostics: ["Non-contrast CT head STAT to rule out hemorrhagic stroke before thrombolytics", "CT angiography (CTA) to identify large vessel occlusion for thrombectomy candidacy", "MRI with diffusion-weighted imaging (DWI) most sensitive for early ischemic changes", "NIHSS (National Institutes of Health Stroke Scale) for severity assessment", "ECG and telemetry monitoring for atrial fibrillation detection", "Blood glucose - hypoglycemia can mimic stroke and must be corrected"],
    management: ["IV alteplase (tPA) within 4.5 hours of symptom onset for eligible patients", "Mechanical thrombectomy for large vessel occlusion within 24 hours in select patients", "Blood pressure management: permissive hypertension unless tPA given (then <180/105)", "Aspirin 325mg within 24-48 hours if tPA not given", "Anticoagulation for cardioembolic stroke (afib) after acute phase", "Statin therapy for atherosclerotic stroke prevention"],
    nursingActions: ["Activate stroke alert immediately - time is brain, note last known well time", "Perform NIHSS assessment rapidly and accurately", "Ensure non-contrast CT head obtained within 25 minutes of arrival", "Administer tPA within 60 minutes of arrival if eligible (door-to-needle time)", "Monitor BP every 15 minutes during and after tPA infusion", "Perform neurological checks every 15 minutes for first 2 hours post-tPA", "Assess for signs of hemorrhagic conversion: sudden headache, vomiting, declining consciousness", "Maintain NPO until swallow screen completed to prevent aspiration"],
    signs: { left: ["Sudden onset focal neurological deficits", "Unilateral weakness or paralysis (hemiparesis/hemiplegia)", "Speech difficulty: expressive aphasia (Broca - frontal) or receptive aphasia (Wernicke - temporal)", "Facial drooping on one side"], right: ["Visual disturbances: hemianopia, diplopia, visual neglect", "Sudden severe headache (more common in hemorrhagic but can occur)", "Dizziness, ataxia, vertigo (posterior circulation stroke)", "Altered level of consciousness in large strokes"] },
    medications: [{ name: "Alteplase (tPA)", type: "Thrombolytic", action: "Tissue plasminogen activator that converts plasminogen to plasmin, which degrades fibrin clot matrix, restoring blood flow to ischemic brain tissue", sideEffects: "Intracranial hemorrhage (6-7% risk), systemic bleeding, angioedema, anaphylaxis", contra: "Active internal bleeding, recent surgery within 14 days, BP >185/110, platelet count <100,000, INR >1.7, blood glucose <50", pearl: "Door-to-needle time goal is 60 minutes. Window is 4.5 hours from last known well. NO anticoagulants or antiplatelets for 24 hours after tPA. Monitor for orolingual angioedema especially in ACE inhibitor users." }],
    pearls: ["Time is brain: approximately 1.9 million neurons die every minute during an ischemic stroke", "The BEFAST mnemonic: Balance, Eyes, Face drooping, Arm weakness, Speech difficulty, Time to call 911", "Last known well time (not when symptoms were discovered) determines tPA eligibility", "Permissive hypertension (up to 220/120) is allowed in ischemic stroke WITHOUT tPA - the elevated BP maintains perfusion to the penumbra"],
    quiz: [{ question: "A patient arrives at the ED with left-sided weakness and aphasia. Symptom onset was 2 hours ago. Non-contrast CT shows no hemorrhage. BP is 192/108. What is the priority action?", options: ["Administer IV labetalol to lower BP below 185/110 and prepare for tPA", "Administer aspirin 325mg immediately", "Schedule MRI for detailed brain imaging", "Observe and recheck BP in 30 minutes"], correct: 0, rationale: "The patient is within the tPA window (4.5 hours) and CT shows no hemorrhage. BP must be lowered below 185/110 before tPA can be given. IV labetalol or nicardipine is used for rapid, controlled BP reduction. Aspirin is contraindicated with tPA and for 24 hours after. MRI should not delay tPA administration." }]
  },

  "hemorrhagic-stroke": {
    title: "Hemorrhagic Stroke",
    cellular: { title: "Intracerebral and Subarachnoid Hemorrhage", content: "Hemorrhagic stroke results from blood vessel rupture within the brain (intracerebral hemorrhage - ICH) or in the subarachnoid space (subarachnoid hemorrhage - SAH). ICH is most commonly caused by hypertensive damage to small penetrating arteries (Charcot-Bouchard microaneurysms) in the basal ganglia, thalamus, pons, and cerebellum. The expanding hematoma compresses surrounding brain tissue, causes edema, and raises intracranial pressure. SAH is most commonly caused by ruptured cerebral aneurysm (berry aneurysm), presenting with thunderclap headache. Both types carry significantly higher mortality than ischemic stroke." },
    riskFactors: ["Chronic uncontrolled hypertension - most common cause of ICH", "Cerebral aneurysm - most common cause of SAH", "Anticoagulant therapy increasing bleeding risk", "Arteriovenous malformation (AVM)", "Cerebral amyloid angiopathy in elderly patients", "Cocaine and amphetamine use causing acute hypertensive crisis", "Coagulopathy: thrombocytopenia, hemophilia, DIC"],
    diagnostics: ["Non-contrast CT head: hyperdense (white) lesion in ICH; blood in subarachnoid space in SAH", "CT angiography for aneurysm or AVM identification", "Lumbar puncture if SAH suspected but CT negative: xanthochromic CSF", "Coagulation studies: PT/INR, aPTT, platelet count", "Cerebral angiography: gold standard for aneurysm characterization"],
    management: ["ICH: aggressive BP reduction (target SBP <140 in first 6 hours)", "Reverse anticoagulation immediately: vitamin K, FFP, PCC, or idarucizumab for dabigatran", "Neurosurgical consultation for hematoma evacuation or aneurysm clipping/coiling", "SAH: nimodipine for vasospasm prevention for 21 days", "ICP management: elevate HOB 30 degrees, osmotic therapy, ventriculostomy if needed", "Seizure prophylaxis in SAH patients"],
    nursingActions: ["Maintain strict BP monitoring and titrate IV antihypertensives as ordered", "Elevate head of bed 30 degrees to promote venous drainage and reduce ICP", "Implement aneurysm precautions for SAH: dim lights, quiet room, no straining, stool softeners", "Perform neurological checks every 1-2 hours including pupil assessment", "Monitor for signs of rebleeding: sudden worsening of headache, vomiting, declining LOC", "Monitor for vasospasm (SAH): new focal deficits typically days 4-14 post-bleed", "Maintain normothermia - fever worsens neurological outcomes", "Ensure seizure precautions are in place"],
    signs: { left: ["ICH: sudden onset severe headache, focal neurological deficits, vomiting, altered LOC", "SAH: thunderclap headache ('worst headache of my life'), nuchal rigidity, photophobia", "Cushing triad (late ICP sign): hypertension, bradycardia, irregular respirations", "Pupil changes: ipsilateral fixed dilated pupil suggests uncal herniation"], right: ["Seizures at onset or early in course", "Nausea and vomiting from increased ICP", "Posterior fossa hemorrhage: sudden vertigo, ataxia, cranial nerve deficits", "Vasospasm (SAH days 4-14): delayed neurological deterioration, new focal deficits"] },
    medications: [{ name: "Nimodipine", type: "Calcium Channel Blocker", action: "Selectively dilates cerebral arteries, reducing vasospasm after subarachnoid hemorrhage and improving neurological outcomes. Does NOT reduce overall mortality but reduces cerebral ischemia from vasospasm", sideEffects: "Hypotension, headache, nausea, diarrhea", contra: "Hypotension (hold if SBP <90), concurrent IV calcium channel blockers", pearl: "Given ORALLY (60mg every 4 hours for 21 days) - do NOT give IV as this causes severe hypotension. If patient cannot swallow, extract from capsule and give via NG tube. It is neuroprotective, not antihypertensive in this context." }],
    pearls: ["Thunderclap headache (maximal intensity at onset) = SAH until proven otherwise, even if CT is negative (sensitivity ~95% at 6 hours, decreasing over time)", "Nimodipine is given ORALLY not IV for SAH vasospasm prevention - IV administration causes dangerous hypotension", "Cushing triad (hypertension, bradycardia, irregular respirations) is a LATE sign of critically elevated ICP and impending brain herniation", "tPA is absolutely CONTRAINDICATED in hemorrhagic stroke - this is why non-contrast CT must be obtained before any thrombolytic therapy"],
    quiz: [{ question: "A patient with a ruptured cerebral aneurysm develops new left-sided weakness on day 7 post-SAH. What complication should the nurse suspect?", options: ["Rebleeding of the aneurysm", "Cerebral vasospasm causing delayed cerebral ischemia", "Hydrocephalus from CSF obstruction", "Seizure activity"], correct: 1, rationale: "Cerebral vasospasm is the most common cause of delayed neurological deterioration after SAH, typically occurring between days 4-14 (peak day 7-10). Vasospasm narrows cerebral arteries, causing ischemia and new focal deficits. Treatment includes hypertensive therapy (triple-H: hypertension, hypervolemia, hemodilution) and possible intra-arterial vasodilators." }]
  },

  "tia-transient-ischemic-attack": {
    title: "Transient Ischemic Attack (TIA)",
    cellular: { title: "Temporary Cerebral Ischemia", content: "A TIA is a transient episode of neurological dysfunction caused by focal brain, spinal cord, or retinal ischemia without acute infarction on imaging. Symptoms typically last minutes to hours (classically less than 1 hour) and resolve completely. The mechanism is identical to ischemic stroke - temporary occlusion of a cerebral artery by a thrombus or embolus that either lyses spontaneously or passes through the vascular bed. TIA is a medical emergency and a warning sign: the 90-day stroke risk after TIA is 10-20%, with the highest risk in the first 48 hours. The ABCD2 score stratifies short-term stroke risk." },
    riskFactors: ["Same risk factors as ischemic stroke", "Carotid artery stenosis - emboli from unstable plaque", "Atrial fibrillation - cardiac emboli", "Recent TIA increases risk of subsequent stroke", "Hypertension, diabetes, hyperlipidemia, smoking"],
    diagnostics: ["MRI with DWI to confirm no acute infarction (defines TIA vs stroke)", "CT angiography of head and neck for carotid stenosis evaluation", "Echocardiography for cardiac embolic sources", "ECG and prolonged cardiac monitoring for atrial fibrillation", "ABCD2 score for risk stratification", "Fasting lipids and HbA1c for modifiable risk factors"],
    management: ["Dual antiplatelet therapy (aspirin + clopidogrel) for 21 days in high-risk TIA", "Statin therapy regardless of cholesterol level", "Carotid endarterectomy for symptomatic stenosis >70%", "Anticoagulation if atrial fibrillation identified", "Aggressive risk factor management: BP control, diabetes management, smoking cessation"],
    nursingActions: ["Treat TIA as a medical emergency - do not dismiss because symptoms resolved", "Perform complete neurological assessment documenting any residual findings", "Obtain ECG and initiate cardiac monitoring for atrial fibrillation detection", "Educate patient on stroke warning signs and need for immediate 911 activation if symptoms recur", "Assess and address modifiable risk factors", "Ensure follow-up imaging and vascular studies are scheduled", "Reinforce medication compliance for secondary prevention"],
    signs: { left: ["Sudden onset transient focal neurological symptoms that resolve completely", "Motor weakness: unilateral arm or leg weakness", "Speech difficulty: slurred speech or word-finding difficulty", "Visual disturbance: amaurosis fugax (monocular vision loss like a curtain descending)"], right: ["Symptoms typically last minutes to 1 hour", "Complete resolution of all neurological deficits", "No evidence of infarction on MRI DWI", "Patient may minimize symptoms because they resolved"] },
    medications: [{ name: "Clopidogrel", type: "Antiplatelet Agent", action: "Irreversibly blocks P2Y12 ADP receptor on platelets, preventing platelet activation and aggregation for secondary stroke prevention", sideEffects: "Bleeding, bruising, GI upset, TTP (rare but serious)", contra: "Active pathological bleeding, severe hepatic impairment", pearl: "Dual antiplatelet therapy (aspirin + clopidogrel) for 21 days after high-risk TIA reduces stroke risk by 30% compared to aspirin alone. After 21 days, continue single antiplatelet agent long-term." }],
    pearls: ["TIA is a stroke warning - 10-20% of TIA patients will have a stroke within 90 days, with the highest risk in the first 48 hours", "Amaurosis fugax (painless transient monocular vision loss) often indicates ipsilateral carotid stenosis with retinal artery embolization", "A TIA with resolved symptoms is NOT benign - it requires urgent workup equivalent to an acute stroke", "The ABCD2 score estimates 2-day stroke risk: Age ≥60, BP ≥140/90, Clinical features (unilateral weakness vs speech), Duration, Diabetes"],
    quiz: [{ question: "A patient reports 30 minutes of right arm weakness and difficulty speaking that has completely resolved. MRI shows no acute infarction. The nurse should:", options: ["Reassure the patient and discharge with primary care follow-up in 2 weeks", "Initiate urgent stroke workup including vascular imaging and cardiac monitoring", "Schedule an outpatient MRI for next week", "Administer tPA since symptoms were stroke-like"], correct: 1, rationale: "TIA is a medical emergency requiring urgent workup. The 48-hour stroke risk is highest immediately after TIA. Vascular imaging (CTA for carotid stenosis), cardiac monitoring (for afib), and initiation of secondary prevention are needed urgently. tPA is not indicated because symptoms have resolved." }]
  },

  "seizure-disorders": {
    title: "Seizure Disorders and Epilepsy",
    cellular: { title: "Abnormal Neuronal Electrical Activity", content: "Seizures result from abnormal, excessive, synchronous electrical discharge of cortical neurons. Normally, excitatory (glutamate) and inhibitory (GABA) neurotransmission are balanced. In seizure disorders, this balance shifts toward excitation through mechanisms including decreased GABA-mediated inhibition, increased glutamate-mediated excitation, altered ion channel function (sodium, calcium, potassium), and loss of surrounding inhibitory interneuron circuits. Generalized seizures involve both hemispheres from onset (tonic-clonic, absence, myoclonic, atonic). Focal seizures originate in one hemisphere and may remain localized or spread (focal to bilateral tonic-clonic). Epilepsy is defined as two or more unprovoked seizures more than 24 hours apart." },
    riskFactors: ["Family history of epilepsy", "Traumatic brain injury", "Stroke or cerebrovascular disease", "Brain tumors or infections (meningitis, encephalitis)", "Perinatal brain injury or developmental abnormalities", "Febrile seizures in childhood (increased risk of epilepsy)", "Alcohol withdrawal", "Metabolic derangements: hypoglycemia, hyponatremia, hypocalcemia, uremia"],
    diagnostics: ["EEG: gold standard for seizure classification and epilepsy diagnosis", "MRI brain: evaluate for structural causes (tumors, malformations, sclerosis)", "Basic metabolic panel: rule out metabolic causes", "Toxicology screen if substance-induced seizure suspected", "Prolactin level: elevated 10-20 minutes post-generalized seizure (helps differentiate from pseudoseizures)", "Video-EEG monitoring for surgical planning or differentiating seizure types"],
    management: ["Antiepileptic drugs (AEDs): first-line based on seizure type", "Broad-spectrum AEDs (levetiracetam, valproate, lamotrigine) for generalized seizures", "Carbamazepine, oxcarbazepine for focal seizures", "Avoid valproate in women of childbearing age (teratogenic - neural tube defects)", "Surgery for medically refractory focal epilepsy with identifiable focus", "Vagus nerve stimulator for refractory cases not surgical candidates"],
    nursingActions: ["During seizure: protect from injury, clear area, do NOT restrain or place anything in mouth", "Time the seizure - duration determines intervention", "Turn to side after seizure to maintain airway (recovery position)", "Maintain seizure precautions: padded side rails, suction at bedside, oxygen available", "Document seizure: type, duration, body parts involved, pre-ictal aura, post-ictal state", "Monitor AED therapeutic levels as ordered", "Educate on seizure triggers: sleep deprivation, stress, alcohol, missed medications", "Assess for medication side effects and compliance"],
    signs: { left: ["Tonic-clonic: stiffening (tonic) followed by rhythmic jerking (clonic), LOC, postictal confusion", "Absence: brief staring episodes (5-30 seconds), no postictal state, common in children", "Focal aware: consciousness preserved, motor/sensory/autonomic symptoms in one area", "Myoclonic: brief shock-like jerking of a muscle group, consciousness usually preserved"], right: ["Atonic (drop attack): sudden loss of muscle tone causing fall, risk of injury", "Focal impaired awareness: altered consciousness with automatisms (lip smacking, hand movements)", "Aura: prodromal sensation (déjà vu, unusual smell, epigastric rising) indicating focal onset", "Postictal state: confusion, fatigue, headache, Todd paralysis (transient focal weakness) after generalized seizure"] },
    medications: [{ name: "Levetiracetam (Keppra)", type: "Anticonvulsant", action: "Binds synaptic vesicle protein SV2A, modulating neurotransmitter release and reducing abnormal neuronal synchronization. Broad-spectrum activity against both focal and generalized seizures", sideEffects: "Behavioral changes (irritability, aggression - 'Keppra rage'), drowsiness, dizziness, fatigue", contra: "Known hypersensitivity. Dose adjustment required in renal impairment", pearl: "First-line for many seizure types due to broad spectrum, minimal drug interactions, no hepatic metabolism, and available IV formulation. Monitor for behavioral side effects especially in patients with psychiatric history." }],
    pearls: ["During a seizure: protect, do NOT restrain, do NOT put anything in the mouth, time the seizure, turn to recovery position after", "Status epilepticus is a seizure lasting more than 5 minutes or repeated seizures without regaining consciousness - this is a medical emergency requiring IV benzodiazepines", "Valproate is highly teratogenic (neural tube defects) - avoid in women of childbearing potential unless no alternative and adequate contraception ensured", "Todd paralysis (transient focal weakness after a seizure) can mimic stroke - it typically resolves within 24-48 hours"],
    quiz: [{ question: "A patient is having a generalized tonic-clonic seizure. Which nursing action is MOST appropriate?", options: ["Insert a padded tongue blade between the teeth to prevent tongue biting", "Restrain the patient's arms and legs to prevent injury", "Protect the head, clear the area of hazards, and time the seizure", "Administer oral lorazepam immediately"], correct: 2, rationale: "During a seizure, the priority is safety: protect the head (pillow or padding), clear objects that could cause injury, and time the seizure. Never insert anything into the mouth (risk of aspiration, broken teeth, injury to the person helping). Never restrain (risk of fractures). Oral medications cannot be given during a seizure - IV benzodiazepines are used for prolonged seizures." }]
  },

  "traumatic-brain-injury": {
    title: "Traumatic Brain Injury",
    cellular: { title: "Primary and Secondary Brain Injury", content: "TBI involves primary injury (mechanical disruption of brain tissue at the moment of impact: contusion, laceration, diffuse axonal injury, intracranial hemorrhage) and secondary injury (subsequent cellular cascades that worsen damage over hours to days: cerebral edema, ischemia, excitotoxicity, oxidative stress, inflammation, and apoptosis). The Glasgow Coma Scale classifies severity: mild (GCS 13-15), moderate (GCS 9-12), severe (GCS 3-8). Secondary brain injury is PREVENTABLE - nursing care focuses on preventing the 'secondary insults' (hypoxia, hypotension, hyperthermia, hyperglycemia, seizures) that dramatically worsen outcomes." },
    riskFactors: ["Motor vehicle collisions - most common cause in adults", "Falls - most common cause in elderly and young children", "Sports-related concussions", "Violence and assault", "Military blast injuries", "Anticoagulant therapy increasing hemorrhage risk after TBI", "Prior TBI increasing vulnerability to subsequent injury"],
    diagnostics: ["GCS assessment: Eye opening, Verbal response, Motor response (best response)", "Non-contrast CT head: contusions, hemorrhage, edema, midline shift, skull fractures", "MRI for diffuse axonal injury and subtle lesions", "ICP monitoring for severe TBI (GCS ≤8)", "Serial neurological examinations for deterioration detection", "CT angiography if vascular injury suspected"],
    management: ["ABCs with C-spine stabilization", "Intubation and mechanical ventilation for GCS ≤8", "ICP monitoring and management: target ICP <22 mmHg and CPP 60-70 mmHg", "Prevent secondary insults: maintain SpO2 >94%, SBP >100, normothermia, euglycemia", "Seizure prophylaxis for 7 days after severe TBI", "Surgical evacuation for expanding epidural or subdural hematomas"],
    nursingActions: ["Perform GCS assessment and document accurately at prescribed intervals", "Maintain C-spine immobilization until cleared", "Monitor ICP and CPP continuously in severe TBI patients", "Prevent secondary insults: avoid hypoxia (SpO2 >94%), hypotension (SBP >100), hyperthermia", "Elevate HOB 30 degrees with head midline", "Monitor for Cushing triad indicating herniation", "Assess pupils every 1-2 hours: size, equality, reactivity", "Monitor blood glucose and treat hyperglycemia (target 80-180 mg/dL)", "Administer seizure prophylaxis as prescribed (levetiracetam or phenytoin for 7 days)", "Provide emotional support to family - TBI has devastating personal and family impact"],
    signs: { left: ["Altered level of consciousness based on GCS scoring", "Pupil changes: unilateral dilation indicates ipsilateral herniation", "Battle sign: mastoid ecchymosis (posterior skull base fracture - appears 12-24 hours)", "Raccoon eyes: bilateral periorbital ecchymosis (anterior skull base fracture)"], right: ["CSF rhinorrhea (nose) or otorrhea (ear): skull base fracture with dural tear", "Seizures: early post-traumatic seizures in 5-10% of severe TBI", "Cushing triad: late sign of herniation", "Diabetes insipidus: dilute polyuria from posterior pituitary damage"] },
    medications: [{ name: "Levetiracetam (Keppra)", type: "Anticonvulsant (Seizure Prophylaxis)", action: "Prevents early post-traumatic seizures (within 7 days) by modulating neurotransmitter release via SV2A binding", sideEffects: "Behavioral changes, drowsiness, dizziness", contra: "None absolute in the TBI setting. Adjust for renal impairment", pearl: "Preferred over phenytoin for seizure prophylaxis in TBI: no drug level monitoring needed, fewer drug interactions, no hepatic induction. Prophylaxis for 7 days reduces early seizures but does NOT prevent epilepsy development." }],
    pearls: ["The secondary insults (hypoxia, hypotension, hyperthermia, hyperglycemia) are PREVENTABLE and dramatically worsen TBI outcomes - nursing vigilance in preventing these is critical", "GCS Motor component is the most prognostic: Motor score of 1-2 = poor prognosis, Motor score of 5-6 = good prognosis", "Battle sign and raccoon eyes are DELAYED signs (12-24 hours) of basilar skull fracture - absence does not rule out fracture in the acute setting", "Do NOT test for CSF leak by inserting anything into the nose or ear - if present, CSF rhinorrhea/otorrhea creates a direct path for meningitis"],
    quiz: [{ question: "A patient with severe TBI (GCS 6) has the following values: ICP 25 mmHg, MAP 78 mmHg. What nursing intervention is most appropriate?", options: ["No intervention needed as values are within normal range", "Administer prescribed mannitol and notify the physician - CPP is below target", "Lower the head of bed flat to increase cerebral blood flow", "Administer IV fluids to increase blood pressure and hyperventilate to PaCO2 of 25"], correct: 1, rationale: "CPP = MAP - ICP = 78 - 25 = 53 mmHg, which is below the target of 60-70 mmHg, and ICP of 25 exceeds the threshold of 22. Mannitol will reduce ICP. The physician should be notified for additional orders. Lowering HOB would worsen ICP. Aggressive hyperventilation to 25 causes cerebral vasoconstriction and ischemia." }]
  },

  "epidural-hematoma": {
    title: "Epidural Hematoma",
    cellular: { title: "Arterial Hemorrhage Between Dura and Skull", content: "An epidural hematoma (EDH) is a collection of blood between the inner skull table and the dura mater, most commonly from a tear in the middle meningeal artery following a temporal bone fracture. Arterial bleeding creates a rapidly expanding, lens-shaped (biconvex) hematoma that compresses the brain. The classic presentation involves a 'lucid interval': initial loss of consciousness from the impact, brief neurological recovery as the brain compensates, followed by rapid deterioration as the expanding hematoma exhausts compensatory mechanisms and causes uncal herniation. Without emergent surgical evacuation (craniotomy), EDH is rapidly fatal." },
    riskFactors: ["Temporal bone fracture disrupting the middle meningeal artery", "Traumatic head injury from falls, MVCs, assaults, sports injuries", "Young adults (epidural space is less adherent to skull)", "Anticoagulant therapy"],
    diagnostics: ["CT head: biconvex (lens-shaped) hyperdense collection that does NOT cross suture lines", "Temporal bone fracture on CT or skull X-ray", "GCS trending for deterioration after lucid interval", "Pupil assessment: ipsilateral fixed dilated pupil from CN III compression"],
    management: ["Emergent neurosurgical evacuation (craniotomy) - this is a surgical emergency", "ICP management while awaiting surgery", "ABC management with intubation for GCS ≤8", "Seizure prophylaxis"],
    nursingActions: ["Recognize the lucid interval pattern: initial LOC → brief improvement → rapid deterioration", "Monitor neurological status continuously after temporal region trauma", "Report ANY deterioration in consciousness immediately", "Assess pupils frequently - unilateral dilation is an emergency", "Prepare for emergent craniotomy", "Maintain ICP management while awaiting surgery: HOB 30°, head midline, osmotic therapy as ordered"],
    signs: { left: ["Initial loss of consciousness from impact", "Lucid interval: temporary improvement in neurological status", "Rapid deterioration: decreasing GCS, contralateral hemiparesis", "Ipsilateral pupil dilation: CN III compression from uncal herniation"], right: ["Cushing triad in late presentation", "Contralateral hemiplegia from cerebral peduncle compression", "CT: biconvex lens-shaped hematoma NOT crossing suture lines", "Temporal bone fracture often visible"] },
    medications: [{ name: "Mannitol", type: "Osmotic Diuretic", action: "Temporarily reduces ICP by osmotic dehydration of brain tissue while the patient is being prepared for emergent surgical evacuation", sideEffects: "Dehydration, electrolyte imbalances, rebound ICP elevation", contra: "Serum osmolality >320 mOsm/L", pearl: "Mannitol is a BRIDGE to surgery in epidural hematoma - it buys time but is NOT definitive treatment. Surgical evacuation is the only cure." }],
    pearls: ["The lucid interval is the hallmark of epidural hematoma - the patient appears to improve then rapidly deteriorates. NEVER discharge a head trauma patient without adequate observation", "Epidural hematoma is biconvex (lens-shaped) on CT and does NOT cross suture lines (because the dura is attached at suture lines)", "Subdural hematoma is crescent-shaped on CT and DOES cross suture lines (between dura and arachnoid)", "Epidural hematoma has the BEST prognosis of all intracranial hemorrhages IF rapidly evacuated - delay is fatal"],
    quiz: [{ question: "A patient hit on the side of the head loses consciousness briefly, then appears alert and oriented. Thirty minutes later, the patient becomes increasingly confused with a dilating left pupil. What is the most likely diagnosis?", options: ["Concussion with prolonged symptoms", "Epidural hematoma with lucid interval and herniation", "Subdural hematoma", "Cerebral contusion"], correct: 1, rationale: "The classic lucid interval (initial LOC → improvement → rapid deterioration) with ipsilateral pupil dilation is pathognomonic for epidural hematoma with uncal herniation. The temporal bone fracture tears the middle meningeal artery, and the arterial bleeding creates a rapidly expanding hematoma. This requires emergent craniotomy." }]
  },

  "spinal-cord-injury": {
    title: "Spinal Cord Injury",
    cellular: { title: "Complete and Incomplete Cord Syndromes", content: "Spinal cord injury (SCI) causes primary mechanical disruption and secondary cascades (ischemia, inflammation, excitotoxicity, apoptosis) that extend the damage. Complete SCI results in total loss of motor and sensory function below the injury level. Incomplete SCI preserves some function. Key incomplete syndromes include: Central cord (upper extremity weakness > lower, common in elderly with cervical spondylosis), Brown-Séquard (hemisection: ipsilateral motor loss and proprioception loss, contralateral pain/temp loss), Anterior cord (motor and pain/temp loss, preserved proprioception), and Posterior cord (loss of proprioception, preserved motor and pain/temp). The ASIA classification grades injury from A (complete) to E (normal)." },
    riskFactors: ["Motor vehicle accidents (most common)", "Falls (most common in elderly)", "Violence (gunshot wounds, stab wounds)", "Sports and recreation injuries (diving into shallow water)", "Ankylosing spondylitis and cervical spondylosis predisposing to cord injury"],
    diagnostics: ["ASIA neurological examination: motor and sensory level assessment", "MRI: gold standard for cord compression, hemorrhage, edema", "CT spine: fracture identification and characterization", "Serial neurological exams every 4-8 hours initially", "Spine X-rays as initial screening"],
    management: ["Spinal immobilization with log-roll precautions", "Airway management: intubation for high cervical injuries (C3-C5 diaphragm risk)", "Hemodynamic support: neurogenic shock management with vasopressors and fluids", "Surgical decompression and stabilization within 24 hours improves outcomes", "Prevention of secondary complications: DVT, pressure injuries, UTI, pneumonia"],
    nursingActions: ["Maintain strict spinal immobilization until surgical stabilization", "Monitor respiratory function closely in cervical injuries: vital capacity, SpO2, work of breathing", "Manage neurogenic shock: IV fluids, vasopressors for hypotension with bradycardia", "Turn patient every 2 hours using log-roll technique to prevent pressure injuries", "Monitor for autonomic dysreflexia in injuries above T6", "Implement DVT prophylaxis", "Bladder management: intermittent catheterization preferred over indwelling", "Bowel program: scheduled bowel care to prevent impaction", "Provide emotional and psychological support", "Begin rehabilitation planning early"],
    signs: { left: ["Complete SCI: total loss of motor and sensory function below injury level", "Central cord: upper extremity weakness > lower extremity, 'man in a barrel'", "Brown-Séquard: ipsilateral motor/proprioception loss, contralateral pain/temp loss", "Neurogenic shock (cervical/high thoracic): hypotension AND bradycardia"], right: ["Spinal shock: temporary loss of all reflexes below injury (areflexia), may last days to weeks", "Poikilothermia: inability to regulate body temperature below injury level", "Priapism: sustained erection from unopposed parasympathetic activity", "Diaphragmatic breathing in high cervical injury (use of accessory muscles)"] },
    medications: [{ name: "Norepinephrine", type: "Vasopressor", action: "Alpha-1 agonist that causes arterial vasoconstriction to treat hypotension from neurogenic shock (loss of sympathetic vasomotor tone below the SCI level)", sideEffects: "Peripheral ischemia, reflex bradycardia, tissue necrosis with extravasation", contra: "Hypovolemia (must rule out hemorrhagic shock first)", pearl: "Neurogenic shock (hypotension + bradycardia) from SCI above T6 requires vasopressors because the sympathetic nervous system is disrupted. MAP target ≥85 mmHg for 7 days after acute SCI to maintain spinal cord perfusion. Atropine may be needed for symptomatic bradycardia." }],
    pearls: ["Neurogenic shock (hypotension + BRADYCARDIA) from SCI vs hypovolemic shock (hypotension + TACHYCARDIA) - always rule out hemorrhagic shock first in trauma patients", "C3-C5 keeps the diaphragm alive - injuries at or above C5 may compromise breathing and require mechanical ventilation", "Autonomic dysreflexia occurs in SCI above T6: sudden severe hypertension triggered by noxious stimuli below injury level (full bladder, constipation) - untreated can cause stroke, seizures, death", "Spinal shock (temporary areflexia) is different from neurogenic shock (hemodynamic instability) - they can co-exist"],
    quiz: [{ question: "A patient with a C4 SCI has BP 72/48 and HR 48. This hemodynamic pattern is consistent with:", options: ["Hypovolemic shock", "Cardiogenic shock", "Neurogenic shock", "Septic shock"], correct: 2, rationale: "Neurogenic shock from cervical SCI causes loss of sympathetic tone below the injury, resulting in vasodilation (hypotension) and unopposed vagal activity (bradycardia). This is the hallmark pattern: hypotension WITH bradycardia. Hypovolemic shock would show tachycardia as compensation. Both can coexist in trauma patients, so bleeding must always be ruled out." }]
  },

  "autonomic-dysreflexia": {
    title: "Autonomic Dysreflexia",
    cellular: { title: "Sympathetic Storm Below SCI Level", content: "Autonomic dysreflexia (AD) is a life-threatening condition occurring in SCI above T6. A noxious stimulus below the injury level (most commonly bladder distension or fecal impaction) triggers an uninhibited sympathetic response: massive vasoconstriction below the injury level causes severe hypertension (SBP can exceed 300 mmHg). Baroreceptors in the carotid sinus and aortic arch detect the hypertension and attempt compensatory parasympathetic response through the vagus nerve: bradycardia, vasodilation, and sweating ABOVE the injury level. However, the descending inhibitory signals from the brainstem cannot cross the injured cord to suppress the sympathetic outflow below the injury, perpetuating the hypertensive crisis. Without treatment, AD can cause stroke, seizures, retinal hemorrhage, MI, and death." },
    riskFactors: ["SCI at T6 or above (sympathetic outflow from T6-L2 is intact below injury)", "Bladder distension: kinked or blocked catheter (most common trigger)", "Fecal impaction or rectal distension", "Skin irritation: pressure injuries, tight clothing, wrinkled sheets", "UTI or bladder stones", "Ingrown toenails, burns, fractures below injury level"],
    diagnostics: ["Severe hypertension: SBP >20-40 mmHg above patient's baseline (often >200 systolic)", "Pounding headache (from hypertension)", "Bradycardia (vagal response to hypertension)", "Clinical diagnosis - do NOT delay treatment for testing"],
    management: ["SIT THE PATIENT UP immediately to induce orthostatic BP reduction", "Identify and remove the noxious stimulus starting with the most common causes", "Check catheter first: kinked? Blocked? Irrigate or replace if needed", "If no catheter: straight catheterize with lidocaine gel", "Check for fecal impaction (use lidocaine gel before digital stimulation)", "If BP remains elevated after stimulus removal: nifedipine or nitroglycerin paste as ordered"],
    nursingActions: ["Recognize AD immediately: sudden headache, hypertension, bradycardia, flushing/sweating above SCI level", "Sit patient UP immediately and lower legs to reduce BP", "Check urinary catheter FIRST - most common trigger is bladder distension", "If catheter is blocked: irrigate or replace immediately", "If no catheter: catheterize with lidocaine gel to prevent worsening AD", "Loosen all tight clothing, check for wrinkled sheets, remove constrictive devices", "Check for fecal impaction if urinary cause is not found", "Monitor BP every 2-5 minutes until crisis resolves", "Administer antihypertensive as ordered if BP remains elevated", "NEVER leave the patient during an AD episode"],
    signs: { left: ["Severe hypertension (SBP often >200 mmHg)", "Pounding headache", "Bradycardia (compensatory vagal response)", "Profuse sweating and flushing ABOVE the level of SCI"], right: ["Piloerection (goosebumps) below injury level", "Nasal congestion", "Blurred vision from hypertension", "Anxiety and sense of doom", "Pale, cool skin BELOW the injury level (vasoconstriction)"] },
    medications: [{ name: "Nifedipine", type: "Calcium Channel Blocker", action: "Arteriolar vasodilator that rapidly lowers blood pressure in autonomic dysreflexia by relaxing vascular smooth muscle", sideEffects: "Hypotension (can be severe - monitor closely), headache, flushing, tachycardia", contra: "Hypotension, aortic stenosis", pearl: "Use immediate-release nifedipine capsule (bite and swallow). Only use if BP remains elevated after removing the triggering stimulus. Monitor BP closely for rebound hypotension. Nitroglycerin paste (2% topical) is an alternative that can be removed if BP drops too low." }],
    pearls: ["Autonomic dysreflexia is a LIFE-THREATENING emergency in SCI above T6 - SBP can exceed 300 mmHg causing stroke, MI, seizures, and death", "The most common trigger is BLADDER DISTENSION (kinked catheter, blocked catheter, full bladder) - ALWAYS check the catheter first", "SIT THE PATIENT UP immediately - this is the single fastest way to reduce BP while identifying and removing the trigger", "Patients and caregivers must be educated to recognize AD and manage it at home - carry an emergency card with instructions"],
    quiz: [{ question: "A patient with T4 SCI suddenly develops a pounding headache, BP 240/120, and HR 52. Profuse sweating is noted on the face and neck. What is the FIRST nursing action?", options: ["Administer IV labetalol for hypertension", "Sit the patient up and check the urinary catheter", "Place the patient flat and call a code blue", "Obtain a STAT CT head to rule out stroke"], correct: 1, rationale: "This is autonomic dysreflexia. The FIRST action is to sit the patient up (induces orthostatic BP drop) and check the urinary catheter (most common trigger is bladder distension from a kinked or blocked catheter). Antihypertensives are given ONLY if BP remains elevated after removing the triggering stimulus. Placing the patient flat would worsen hypertension." }]
  },

  "guillain-barre-syndrome": {
    title: "Guillain-Barré Syndrome",
    cellular: { title: "Ascending Inflammatory Demyelinating Polyneuropathy", content: "Guillain-Barré syndrome (GBS) is an acute autoimmune attack on the peripheral nervous system, typically triggered by a preceding infection (Campylobacter jejuni most common, also CMV, EBV, Zika virus). Molecular mimicry between infectious antigens and peripheral nerve myelin gangliosides causes cross-reactive antibodies to attack the myelin sheath and Schwann cells of peripheral nerves. Demyelination disrupts nerve conduction, causing ascending symmetrical weakness starting in the legs and progressing upward (ascending paralysis). Respiratory failure from diaphragm and intercostal muscle weakness is the most dangerous complication, occurring in 25-30% of patients. Most patients recover fully, but 5-10% have significant residual disability." },
    riskFactors: ["Preceding infectious illness 1-4 weeks before onset (GI or respiratory)", "Campylobacter jejuni gastroenteritis (most strongly associated)", "Recent surgery or vaccination (rare association)", "HIV infection", "Hodgkin lymphoma"],
    diagnostics: ["Lumbar puncture: albuminocytologic dissociation (elevated protein with normal cell count)", "Nerve conduction studies: slowed conduction velocities confirming demyelination", "Serial pulmonary function testing: vital capacity monitoring", "Clinical presentation: ascending symmetric weakness with areflexia", "Rule out other causes: MRI spine, electrolytes, botulism screening"],
    management: ["ICU admission for monitoring respiratory function", "Plasma exchange (PLEX) or IV immunoglobulin (IVIg) - equally effective, started early", "Mechanical ventilation for vital capacity <20 mL/kg or declining respiratory function", "DVT prophylaxis during immobilization", "Pain management: neuropathic pain agents (gabapentin, pregabalin)", "Physical therapy beginning in acute phase"],
    nursingActions: ["Monitor respiratory function every 2-4 hours: vital capacity, negative inspiratory force, SpO2", "Report vital capacity <20 mL/kg or decreasing trend - intubation may be needed", "Monitor for autonomic dysfunction: BP fluctuations, cardiac arrhythmias, urinary retention", "Continuous cardiac telemetry for dysrhythmias", "Assess ascending weakness progression: can patient lift arms? Swallow? Breathe?", "Turn every 2 hours and maintain skin integrity", "Provide emotional support - sudden paralysis is terrifying", "Maintain nutrition: NG tube or parenteral if dysphagia present", "Pain management: GBS neuropathic pain can be severe"],
    signs: { left: ["Ascending symmetric weakness: starts in feet/legs, progresses to arms, trunk, face, respiratory muscles", "Areflexia (absent deep tendon reflexes)", "Sensory symptoms: paresthesias, pain (but motor weakness predominates)", "Bilateral facial weakness (facial diplegia) in some patients"], right: ["Respiratory failure from diaphragm weakness (life-threatening)", "Autonomic dysfunction: labile BP, tachycardia, bradycardia, urinary retention, ileus", "Neuropathic pain: severe burning, aching pain in back and extremities", "Peak weakness reached within 2-4 weeks, then plateau, then gradual recovery"] },
    medications: [{ name: "IV Immunoglobulin (IVIg)", type: "Immunomodulator", action: "Pooled IgG antibodies that modulate the immune response by blocking Fc receptors, neutralizing pathogenic antibodies, and inhibiting complement activation to halt the autoimmune attack on peripheral nerve myelin", sideEffects: "Headache, fever, chills, nausea, anaphylaxis (IgA-deficient patients), aseptic meningitis, renal failure, thrombotic events", contra: "IgA deficiency with anti-IgA antibodies (anaphylaxis risk), severe renal impairment", pearl: "Given 0.4 g/kg/day for 5 days. Must be started within 2 weeks of symptom onset for maximum benefit. Check IgA level before first dose to screen for IgA deficiency. Monitor renal function throughout course. Equally effective as plasma exchange." }],
    pearls: ["GBS is an ASCENDING paralysis (starts in legs, goes up) while MS and stroke cause DESCENDING or focal deficits - this pattern helps differentiate", "Respiratory failure occurs in 25-30% of GBS patients - serial vital capacity monitoring is ESSENTIAL for predicting intubation need", "Albuminocytologic dissociation (high protein, normal cells in CSF) is the classic LP finding but may be normal in the first week", "GBS pain is often underrecognized - severe neuropathic pain occurs in 50-70% of patients and requires adequate treatment"],
    quiz: [{ question: "A patient with GBS has a vital capacity of 18 mL/kg, down from 25 mL/kg yesterday. What is the priority nursing action?", options: ["Continue monitoring and recheck in 8 hours", "Notify the physician immediately - intubation may be needed", "Encourage incentive spirometry", "Position the patient supine to improve breathing"], correct: 1, rationale: "Vital capacity <20 mL/kg is a critical threshold for intubation consideration in GBS. The declining trend (25 → 18) indicates progressive respiratory muscle weakness. The physician must be notified immediately to prepare for intubation before respiratory arrest occurs. Waiting to recheck in 8 hours could be fatal." }]
  },

  "meningitis": {
    title: "Meningitis",
    cellular: { title: "Meningeal Inflammation", content: "Meningitis is inflammation of the meninges (pia mater, arachnoid, dura mater) surrounding the brain and spinal cord. Bacterial meningitis is a medical emergency: bacteria reach the CSF via hematogenous spread, direct extension (sinusitis, otitis), or direct inoculation (trauma, surgery). In the CSF, bacteria multiply rapidly because the CNS has limited immune defense (no complement or immunoglobulins). The inflammatory response (neutrophil infiltration, cytokine release, blood-brain barrier disruption) causes cerebral edema, increased ICP, and cortical ischemia. Common organisms: Streptococcus pneumoniae and Neisseria meningitidis in adults; Group B Strep and E. coli in neonates. Viral meningitis (enterovirus most common) is generally self-limiting." },
    riskFactors: ["Immunocompromised states: HIV, asplenia, complement deficiency", "Close living quarters: college dorms, military barracks", "Age extremes: neonates and elderly", "Lack of meningococcal vaccination", "CSF leak from skull base fracture or surgery", "Cochlear implants", "Recent neurosurgery or VP shunt"],
    diagnostics: ["Lumbar puncture with CSF analysis - definitive diagnostic test", "Bacterial CSF: elevated WBC (PMN predominant), elevated protein, LOW glucose, positive Gram stain/culture", "Viral CSF: elevated WBC (lymphocyte predominant), normal-mildly elevated protein, NORMAL glucose", "Blood cultures before antibiotics (but do NOT delay antibiotics for LP)", "CT head BEFORE LP only if focal deficits, papilledema, immunocompromised, or altered consciousness"],
    management: ["Empiric IV antibiotics IMMEDIATELY - do NOT delay for LP or CT", "Empiric regimen: ceftriaxone + vancomycin (± ampicillin if >50 years for Listeria coverage)", "Dexamethasone BEFORE or WITH first antibiotic dose (reduces inflammatory damage)", "Droplet precautions for suspected N. meningitidis until 24 hours of antibiotics", "Close contact prophylaxis: rifampin or ciprofloxacin for N. meningitidis contacts"],
    nursingActions: ["Administer antibiotics WITHIN 1 HOUR of suspicion - this is the priority", "Implement droplet precautions until meningococcal meningitis is ruled out", "Maintain dim, quiet environment: photophobia and noise sensitivity", "Monitor neurological status: GCS, pupil reactivity, seizure activity", "Monitor for increased ICP signs: altered LOC, vomiting, pupil changes", "Assess for petechial rash: N. meningitidis can cause meningococcemia with DIC", "Monitor for seizures and implement seizure precautions", "Strict I&O monitoring for SIADH (common complication)", "Identify close contacts for prophylaxis"],
    signs: { left: ["Classic triad: fever, nuchal rigidity (stiff neck), altered mental status", "Severe headache with photophobia", "Kernig sign: pain with knee extension when hip is flexed to 90°", "Brudzinski sign: involuntary hip flexion when neck is passively flexed"], right: ["Petechial/purpuric rash: meningococcal meningitis with DIC", "Seizures from cortical irritation", "Nausea and vomiting from increased ICP", "Infants: bulging fontanelle, high-pitched cry, poor feeding, irritability"] },
    medications: [{ name: "Ceftriaxone", type: "Third-Generation Cephalosporin", action: "Bactericidal antibiotic that inhibits bacterial cell wall synthesis. Excellent CNS penetration when meninges are inflamed. Covers most common bacterial meningitis pathogens", sideEffects: "Allergic reaction, diarrhea, biliary sludge, C. difficile", contra: "Severe penicillin allergy with anaphylaxis (use meropenem alternative), neonates with hyperbilirubinemia", pearl: "Combined with vancomycin for empiric coverage (ceftriaxone-resistant pneumococcus). Add ampicillin for patients >50 years or immunocompromised (Listeria coverage). Dexamethasone given BEFORE or WITH the first antibiotic dose reduces mortality in pneumococcal meningitis." }],
    pearls: ["In bacterial meningitis, ANTIBIOTICS FIRST - never delay antibiotics waiting for LP, CT, or culture results. Every hour of delay increases mortality", "CSF glucose is LOW in bacterial meningitis (bacteria consume glucose) and NORMAL in viral meningitis - this is a key differentiator", "Dexamethasone must be given BEFORE or WITH the first dose of antibiotics, not after - it reduces inflammatory damage and mortality in pneumococcal meningitis", "Meningococcal meningitis requires droplet precautions AND prophylaxis for close contacts (household members, kissing contacts, healthcare workers performing mouth-to-mouth)"],
    quiz: [{ question: "A patient presents with fever, nuchal rigidity, and altered mental status. LP shows WBC 2500 (90% PMNs), protein 250, glucose 20, and gram-positive diplococci. Which organism is most likely?", options: ["Neisseria meningitidis", "Streptococcus pneumoniae", "Enterovirus", "Haemophilus influenzae"], correct: 1, rationale: "Gram-positive diplococci (lancet-shaped) are characteristic of Streptococcus pneumoniae, the most common cause of bacterial meningitis in adults. N. meningitidis is gram-negative diplococci. The CSF profile (high WBC with PMN predominance, high protein, LOW glucose) confirms bacterial meningitis." }]
  },

  "alzheimers-disease": {
    title: "Alzheimer Disease",
    cellular: { title: "Progressive Neurodegeneration", content: "Alzheimer disease is the most common cause of dementia, characterized by progressive accumulation of extracellular amyloid-beta (Aβ) plaques and intracellular neurofibrillary tangles (hyperphosphorylated tau protein) in the brain. Aβ plaques disrupt synaptic function and trigger inflammatory cascades. Tau tangles destabilize microtubules, disrupting intracellular transport and leading to neuronal death. The disease begins in the entorhinal cortex and hippocampus (memory centers), then spreads to the temporal, parietal, and frontal cortices. Cholinergic neurons in the nucleus basalis of Meynert are particularly affected, causing acetylcholine depletion. The disease progresses through mild cognitive impairment (MCI), mild, moderate, and severe stages over 8-12 years." },
    riskFactors: ["Age: strongest risk factor (doubles every 5 years after age 65)", "APOE ε4 allele: most important genetic risk factor for late-onset AD", "Family history of AD", "Down syndrome (trisomy 21): gene for amyloid precursor protein on chromosome 21", "Cardiovascular risk factors: hypertension, diabetes, hyperlipidemia", "Low educational attainment and cognitive inactivity", "Head trauma history", "Depression"],
    diagnostics: ["Clinical assessment: progressive memory loss and cognitive decline affecting daily function", "Mini-Mental State Examination (MMSE) or Montreal Cognitive Assessment (MoCA)", "MRI: hippocampal and medial temporal lobe atrophy", "PET scan: amyloid and tau imaging", "CSF biomarkers: decreased Aβ42, elevated tau and phospho-tau", "Rule out reversible causes of dementia: B12 deficiency, hypothyroidism, NPH, depression"],
    management: ["Cholinesterase inhibitors (donepezil, rivastigmine, galantamine) for mild-moderate disease", "NMDA receptor antagonist (memantine) for moderate-severe disease", "Combination therapy: cholinesterase inhibitor + memantine for moderate-severe", "Non-pharmacologic: structured routine, cognitive stimulation, physical activity, social engagement", "Behavioral management: identify triggers for agitation, redirect, create safe environment", "Caregiver support and education: respite care, support groups, long-term planning"],
    nursingActions: ["Maintain consistent daily routine to reduce confusion and agitation", "Use simple, one-step commands and allow time for processing", "Provide a safe environment: remove hazards, lock doors if wandering risk, identify bracelet", "Reorient as needed but do NOT argue with hallucinations or delusions (redirect instead)", "Monitor nutritional status - patients forget to eat or lose ability to feed independently", "Assess for depression, which can worsen cognitive function", "Support caregivers: assess burden, provide education, refer to support resources", "Plan for progressive decline: advance directives while patient can still participate", "Promote independence as much as safely possible"],
    signs: { left: ["Early: short-term memory loss, difficulty with complex tasks, word-finding difficulty", "Moderate: confusion about time and place, poor judgment, personality changes, paranoia", "Severe: inability to recognize family, loss of speech, incontinence, complete dependence", "Agitation and sundowning: worsening confusion in late afternoon/evening"], right: ["Aphasia: progressive language difficulties (naming, comprehension, fluency)", "Apraxia: inability to perform learned motor tasks despite intact motor function", "Agnosia: inability to recognize objects, faces, or people", "Executive dysfunction: impaired planning, organizing, sequencing"] },
    medications: [{ name: "Donepezil (Aricept)", type: "Cholinesterase Inhibitor", action: "Reversibly inhibits acetylcholinesterase, increasing acetylcholine concentration in synaptic clefts to partially compensate for the cholinergic deficit in Alzheimer disease. Does NOT stop disease progression but temporarily improves or stabilizes cognitive function", sideEffects: "GI effects: nausea, diarrhea, anorexia, weight loss. Bradycardia, syncope. Vivid dreams/insomnia (give in the morning if insomnia occurs)", contra: "Sick sinus syndrome or AV block without pacemaker (bradycardia risk), active GI bleeding", pearl: "Start low (5mg/day) and increase to 10mg after 4-6 weeks. Give at bedtime (unless insomnia occurs). Cholinesterase inhibitors do NOT cure or stop AD progression - they temporarily improve symptoms by about 6-12 months. Benefits should be reassessed periodically." }],
    pearls: ["Alzheimer disease is the most common form of dementia (60-80% of cases)", "Sundowning (increased agitation in late afternoon/evening) is common - maintain adequate lighting, structured evening routine, and avoid overstimulation", "Never argue with a patient's delusions or hallucinations - redirect their attention to a pleasant activity or topic", "Cholinesterase inhibitors do NOT stop disease progression - they temporarily improve symptoms. Set realistic expectations with families"],
    quiz: [{ question: "A patient with moderate Alzheimer disease insists that a deceased spouse is still alive and waiting for them at home. The most appropriate nursing response is:", options: ["Explain gently that the spouse has died", "Redirect the conversation to a pleasant topic or activity", "Agree completely that the spouse is waiting", "Provide detailed reality orientation about the spouse's death"], correct: 1, rationale: "In moderate-severe Alzheimer disease, confronting the patient with painful reality (spouse's death) causes distress without therapeutic benefit, as the patient will likely forget the information and re-experience grief. Therapeutic communication involves validation of feelings and gentle redirection to a pleasant activity or conversation, not arguing with or reinforcing the delusion." }]
  },

  "bell-palsy": {
    title: "Bell Palsy",
    cellular: { title: "Acute Idiopathic Facial Nerve Paralysis", content: "Bell palsy is an acute, idiopathic, unilateral lower motor neuron paralysis of the facial nerve (CN VII). The facial nerve swells within the narrow fallopian canal of the temporal bone, causing ischemia and dysfunction. HSV-1 reactivation is the leading suspected etiology. Because it is a lower motor neuron lesion, the ENTIRE ipsilateral face is affected (including the forehead), distinguishing it from an upper motor neuron lesion (stroke), which spares the forehead. The prognosis is good: 70-80% of patients recover completely within 3-6 months." },
    riskFactors: ["HSV-1 infection (likely trigger)", "Diabetes mellitus", "Pregnancy (third trimester, postpartum)", "Upper respiratory infection", "Immunocompromised state", "Age 15-45 years most common"],
    diagnostics: ["Clinical diagnosis: acute onset unilateral facial paralysis involving the entire half of face", "Distinguish from stroke: forehead involvement (LMN) vs forehead sparing (UMN)", "Rule out other causes: Lyme disease, tumors, Ramsay Hunt syndrome (herpes zoster oticus)", "Facial nerve EMG if no improvement by 2 weeks"],
    management: ["Corticosteroids (prednisone 60-80mg/day for 7-10 days) started within 72 hours", "Antiviral (valacyclovir) may be added to steroids though benefit is debated", "Eye protection: artificial tears, eye patching, tape eye closed at night", "Facial exercises and physical therapy during recovery", "Surgical decompression rarely needed"],
    nursingActions: ["Protect the eye on the affected side: cannot close eyelid, cornea at risk", "Apply artificial tears frequently during the day", "Tape the eye closed or use moisture chamber at night", "Provide emotional support: facial paralysis is distressing and affects self-image", "Educate that most cases recover fully within 3-6 months", "Teach facial exercises to maintain muscle tone", "Assess for Ramsay Hunt syndrome: vesicular eruption on the ear (worse prognosis)"],
    signs: { left: ["Sudden onset unilateral facial paralysis involving ENTIRE half of face (upper and lower)", "Inability to close the eye on affected side (lagophthalmos)", "Drooping of the mouth corner, drooling", "Loss of taste on anterior 2/3 of tongue on affected side"], right: ["Hyperacusis: increased sensitivity to sound on affected side (stapedius muscle paralysis)", "Decreased tearing on affected side initially, then excess tearing from incomplete eye closure", "Difficulty eating and drinking from affected side", "Forehead involvement distinguishes from stroke (LMN vs UMN lesion)"] },
    medications: [{ name: "Prednisone", type: "Corticosteroid", action: "Reduces inflammation and edema of the facial nerve within the fallopian canal, restoring blood flow and improving nerve function recovery", sideEffects: "Short-term: insomnia, mood changes, hyperglycemia, GI irritation. Long-term risks minimal with 7-10 day course", contra: "Active infection (relative), diabetes (monitor glucose closely)", pearl: "Must be started within 72 hours of symptom onset for maximum benefit. Standard dose is 60-80mg daily for 7-10 days with taper. Steroids significantly improve the rate and completeness of recovery." }],
    pearls: ["Bell palsy (LMN) affects the ENTIRE ipsilateral face including forehead; stroke (UMN) spares the forehead - this distinction is critical for emergency assessment", "Eye protection is the most important nursing intervention - inability to close the eye leads to corneal drying, ulceration, and potentially permanent vision loss", "Most patients (70-80%) recover completely within 3-6 months - reassure the patient", "Ramsay Hunt syndrome (herpes zoster oticus) presents similarly to Bell palsy but with vesicular eruption on the ear - it has a worse prognosis and requires antivirals"],
    quiz: [{ question: "A patient presents with sudden right-sided facial drooping. They cannot wrinkle the right forehead, close the right eye, or smile on the right side. The left side of the face is normal. Is this a stroke or Bell palsy?", options: ["Stroke - because any facial drooping is a stroke until proven otherwise", "Bell palsy - because the ENTIRE right face is affected including the forehead, indicating a lower motor neuron lesion", "Cannot be determined without CT scan", "Stroke - because the right side is affected"], correct: 1, rationale: "Involvement of the ENTIRE ipsilateral face (including the forehead) indicates a lower motor neuron lesion (Bell palsy). A stroke (upper motor neuron lesion) would spare the forehead because the upper face receives bilateral cortical innervation. However, stroke should still be ruled out in the emergency setting, especially if other neurological deficits are present." }]
  },

  "seizure-precautions": {
    title: "Seizure Precautions and Safety",
    cellular: { title: "Environmental Safety for Seizure-Prone Patients", content: "Seizure precautions are a set of safety measures implemented for patients at risk for seizures to prevent injury during ictal events. During a generalized tonic-clonic seizure, the patient loses consciousness and has uncontrolled muscle contractions that can cause falls, head trauma, aspiration, and fractures. The post-ictal period may include confusion, weakness, and airway compromise. Environmental modifications, equipment availability, and nursing vigilance are the cornerstones of seizure safety. Patients at highest risk include those with known epilepsy, acute brain injury, metabolic derangements, alcohol withdrawal, and post-neurosurgical procedures." },
    riskFactors: ["Known epilepsy with recent seizure activity", "Acute brain injury: TBI, stroke, hemorrhage", "Post-craniotomy or neurosurgical procedure", "Alcohol or benzodiazepine withdrawal", "Metabolic derangements: hyponatremia, hypoglycemia, hypocalcemia, uremia", "Eclampsia in pregnancy", "Medication non-compliance in known epilepsy patients"],
    diagnostics: ["Risk assessment based on history, diagnosis, and clinical status", "EEG monitoring for high-risk patients", "Metabolic panel to identify correctable seizure triggers", "AED drug levels if on anticonvulsant therapy"],
    management: ["Implement seizure precautions per institutional protocol", "Ensure IV access is maintained", "Keep bed in lowest position with side rails padded", "Suction and oxygen at bedside", "Oral airway (NOT to be inserted during seizure) at bedside"],
    nursingActions: ["Pad side rails with soft material to prevent injury during seizure", "Keep bed in lowest position at all times", "Place suction equipment, oral airway, and oxygen at bedside", "Ensure IV access is patent and functional", "Remove sharp objects and clutter from the bedside area", "Keep patient supervised or on continuous monitoring", "During seizure: protect head, do NOT restrain, do NOT insert anything in mouth, turn to side after", "Time every seizure - duration determines intervention threshold (>5 minutes = emergency)", "Document: time of onset, type of activity, body parts involved, duration, post-ictal state", "Administer AEDs on schedule - never skip doses"],
    signs: { left: ["Aura: warning symptoms before seizure (taste, smell, déjà vu, visual changes)", "Tonic phase: stiffening, may fall if standing, apnea, cyanosis", "Clonic phase: rhythmic jerking movements of extremities", "Post-ictal: confusion, sleepiness, headache, temporary weakness (Todd paralysis)"], right: ["Autonomic signs: excessive salivation, urinary/fecal incontinence, tachycardia", "Injury risk: tongue biting (lateral tongue), falls, fractures", "Aspiration risk from secretions and decreased consciousness", "Status epilepticus: seizure >5 minutes or repeated without recovery"] },
    medications: [{ name: "Diazepam Rectal Gel (Diastat)", type: "Benzodiazepine (Rescue)", action: "Enhances GABA-A receptor activity to terminate prolonged seizures in out-of-hospital or non-IV access settings", sideEffects: "Respiratory depression, sedation, hypotension", contra: "Respiratory depression, narrow-angle glaucoma", pearl: "Prescribed for home/school use for patients with known seizure history when IV access is unavailable. Caregivers must be trained on administration. Call 911 if seizure does not stop within 5 minutes of administration." }],
    pearls: ["NEVER put anything in the mouth during a seizure - this risks aspiration, broken teeth, and injury to the patient and rescuer", "NEVER restrain during a seizure - this can cause fractures and does not stop the seizure", "Turn to SIDE after seizure (recovery position) to maintain airway and prevent aspiration", "Time every seizure - seizures lasting >5 minutes require emergent benzodiazepine treatment (status epilepticus protocol)"],
    quiz: [{ question: "A nursing student is caring for a patient on seizure precautions. Which action by the student requires immediate intervention by the nurse?", options: ["Padding the side rails of the bed", "Keeping suction equipment at the bedside", "Placing a tongue blade taped to the head of the bed 'in case of seizure'", "Keeping the bed in the lowest position"], correct: 2, rationale: "Placing a tongue blade (or any object) at the bedside for insertion into the mouth during a seizure is INCORRECT and dangerous. Nothing should ever be placed in a seizing patient's mouth - it can cause aspiration of the object, broken teeth, and jaw injury. Padded side rails, suction equipment, and low bed position are all correct seizure precautions." }]
  },

  "gcs-assessment": {
    title: "Glasgow Coma Scale Assessment",
    cellular: { title: "Standardized Consciousness Assessment", content: "The Glasgow Coma Scale (GCS) is a standardized neurological assessment tool measuring level of consciousness based on three components: Eye opening (E: 1-4), Verbal response (V: 1-5), and Motor response (M: 1-6). Total score ranges from 3 (deepest coma) to 15 (fully alert). GCS was developed to standardize communication about consciousness levels among healthcare providers. The motor component is the most prognostically significant. GCS is used to classify TBI severity (mild 13-15, moderate 9-12, severe 3-8), guide treatment decisions (intubation at GCS ≤8), and track neurological changes over time." },
    riskFactors: ["Traumatic brain injury", "Stroke (ischemic or hemorrhagic)", "Intoxication or overdose", "Metabolic encephalopathy", "CNS infection", "Post-cardiac arrest", "Seizure (post-ictal state)"],
    diagnostics: ["Eye Opening: Spontaneous (4), To voice (3), To pain (2), None (1)", "Verbal Response: Oriented (5), Confused (4), Inappropriate words (3), Incomprehensible sounds (2), None (1)", "Motor Response: Obeys commands (6), Localizes pain (5), Withdrawal (4), Abnormal flexion/decorticate (3), Extension/decerebrate (2), None (1)", "Record BEST response for each component", "Note if factors prevent accurate assessment (intubated = V1T, eye swelling = ENC)"],
    management: ["GCS ≤8: intubation for airway protection (cannot protect own airway)", "GCS 13-15: mild TBI, may be observed or discharged with precautions", "GCS 9-12: moderate TBI, requires admission and close monitoring", "GCS 3-8: severe TBI, requires ICU admission, likely ICP monitoring", "Any GCS drop of 2+ points requires immediate physician notification"],
    nursingActions: ["Assess GCS at prescribed intervals (every 1-2 hours in acute patients)", "ALWAYS assess and record the BEST response for each component", "Apply central pain stimulus for non-responsive patients: trapezius squeeze, sternal rub", "Do NOT use peripheral pain (nail bed pressure) to assess motor response - it only tests withdrawal reflex", "Document individual components (E3V4M5 = 12) not just the total score", "Report ANY decline in GCS immediately", "Note confounding factors: sedation, paralysis, intubation, orbital swelling", "Ensure consistency between nurses in assessment technique"],
    signs: { left: ["GCS 15: fully alert, oriented, follows commands - normal", "GCS 13-15: mild impairment, may have confusion but follows commands", "GCS 9-12: moderate impairment, localizes pain, confused verbal responses", "GCS 3-8: severe impairment, no eye opening, abnormal motor responses or none"], right: ["Decorticate posturing (M3): arms flexed to chest, legs extended - cortical damage", "Decerebrate posturing (M2): arms and legs extended and internally rotated - brainstem damage", "Pupil changes occurring alongside GCS decline suggest herniation", "GCS 3 with fixed dilated pupils carries grave prognosis"] },
    medications: [{ name: "Assessment Tool - No Medication", type: "Clinical Assessment", action: "GCS is an assessment tool, not a treatment. Accurate and consistent GCS assessment guides medical and surgical decision-making", sideEffects: "N/A", contra: "N/A", pearl: "The motor component (M1-M6) carries the most prognostic weight. A patient with E1V1M5 (GCS 7) who localizes pain has a significantly better prognosis than E1V1M1 (GCS 3) with no motor response. Always report the individual components, not just the total." }],
    pearls: ["GCS of 8 = 'intubate' - a patient with GCS ≤8 cannot reliably protect their airway", "The Motor component is the MOST prognostically significant component of the GCS", "Always record individual components (E3V4M5=12) in addition to the total - a decline in any single component may be missed if only tracking the total", "Central pain stimulation (trapezius squeeze) is more reliable than peripheral (nail bed) for motor assessment - peripheral stimulation may produce a spinal withdrawal reflex rather than a true cortical response"],
    quiz: [{ question: "A patient opens eyes to voice, speaks in confused sentences, and localizes pain with the right arm. What is the GCS score?", options: ["GCS 10 (E3V3M4)", "GCS 12 (E3V4M5)", "GCS 14 (E3V5M6)", "GCS 8 (E2V3M3)"], correct: 1, rationale: "Eye opening to voice = E3. Confused speech (sentences but disoriented) = V4. Localizing pain (reaching purposefully toward painful stimulus) = M5. Total GCS = 3 + 4 + 5 = 12. This indicates moderate brain injury requiring close monitoring." }]
  },

  "lumbar-puncture": {
    title: "Lumbar Puncture",
    cellular: { title: "CSF Sampling and Analysis", content: "Lumbar puncture (LP) involves inserting a spinal needle into the subarachnoid space of the lumbar cistern (typically L3-L4 or L4-L5 interspace, below the conus medullaris) to obtain cerebrospinal fluid for diagnostic analysis. CSF is produced by choroid plexus in the ventricles (500 mL/day, total volume 150 mL). Normal CSF is clear, colorless, with glucose 50-80 mg/dL (60% of serum glucose), protein 15-45 mg/dL, and WBC 0-5 cells/μL (all lymphocytes). Opening pressure is 10-20 cm H2O. LP is diagnostic for meningitis, SAH, MS, Guillain-Barré syndrome, and pseudotumor cerebri. It is also therapeutic in pseudotumor cerebri and normal pressure hydrocephalus." },
    riskFactors: ["Increased ICP (risk of herniation with LP - obtain CT head first if suspected)", "Coagulopathy or thrombocytopenia (bleeding risk)", "Infection at the puncture site", "Spinal deformity making access difficult", "Obesity making landmark identification difficult"],
    diagnostics: ["Opening pressure measurement: elevated >20 cm H2O suggests increased ICP or pseudotumor cerebri", "Cell count and differential: elevated WBC indicates infection or inflammation", "Protein: elevated in infection, GBS, tumors", "Glucose: decreased in bacterial meningitis (bacteria consume glucose)", "Gram stain, culture, and sensitivity for infectious organisms", "Oligoclonal bands for MS diagnosis", "Cytology for malignant cells in carcinomatous meningitis", "Xanthochromia (yellow CSF) for SAH diagnosis when CT negative"],
    management: ["CT head BEFORE LP if: focal deficits, papilledema, altered consciousness, immunocompromised", "Position: lateral decubitus (fetal position) or seated with back curved to open interspinous spaces", "Sterile technique throughout procedure", "Post-LP: flat for 1-2 hours, increase fluids, monitor for headache", "Manage post-LP headache: bed rest, fluids, caffeine, autologous epidural blood patch if persistent"],
    nursingActions: ["Verify consent and explain procedure to patient", "Position patient correctly: lateral decubitus with knees drawn to chest and chin tucked, or seated bending forward", "Assist with sterile setup and maintain sterile field", "Label CSF tubes in order (Tube 1-4) and transport to lab promptly", "Post-LP: keep patient flat for 1-2 hours per protocol", "Encourage oral fluid intake (2-3 L/day) to promote CSF production and prevent headache", "Monitor for post-LP headache: positional headache (worse sitting/standing, better lying flat)", "Assess puncture site for bleeding, CSF leak, or signs of infection", "Monitor neurological status and lower extremity function"],
    signs: { left: ["Normal CSF: clear, colorless, opening pressure 10-20 cm H2O", "Bacterial meningitis: cloudy CSF, elevated WBC (PMNs), elevated protein, LOW glucose", "Viral meningitis: clear CSF, elevated WBC (lymphocytes), normal-slight elevated protein, NORMAL glucose", "SAH: xanthochromic (yellow) CSF, elevated RBCs that do NOT clear between tubes"], right: ["Post-LP headache: positional headache worse upright, better lying flat (2-3 days post-LP)", "Post-LP back pain: localized at puncture site, usually mild", "Infection: rare, presents as meningitis days after procedure", "Nerve root irritation: transient radiculopathy during needle insertion"] },
    medications: [{ name: "Caffeine Sodium Benzoate", type: "CNS Stimulant / Cerebral Vasoconstrictor", action: "Causes cerebral vasoconstriction, reducing compensatory vasodilation that occurs from low CSF pressure after lumbar puncture, thereby treating post-LP headache", sideEffects: "Tachycardia, insomnia, tremor, GI upset", contra: "Severe cardiac arrhythmias, anxiety disorders", pearl: "For post-LP headache, encourage oral caffeine (coffee, cola) first. If severe positional headache persists >24-48 hours, an autologous epidural blood patch is the definitive treatment - the patient's own blood is injected into the epidural space to seal the dural puncture." }],
    pearls: ["CT head must be obtained BEFORE LP if increased ICP is suspected - LP in the setting of increased ICP can cause transtentorial herniation", "CSF glucose below 40 mg/dL or less than 60% of serum glucose strongly suggests bacterial meningitis", "Post-LP headache is a POSITIONAL headache: worse when sitting/standing, better when lying flat - this is due to ongoing CSF leak from the dural puncture site", "Traumatic tap (blood introduced during needle insertion) shows RBCs that DECREASE from tube 1 to tube 4; SAH shows RBCs that remain CONSISTENT across all tubes"],
    quiz: [{ question: "A patient had a lumbar puncture 4 hours ago and reports a severe headache that worsens when sitting up and improves when lying flat. What is the most appropriate nursing intervention?", options: ["Administer IV morphine for pain control", "Keep the patient in a flat position and encourage fluids", "Sit the patient up and administer oxygen", "Prepare for an emergent CT head"], correct: 1, rationale: "This is a classic post-LP headache: positional (worse upright, better supine) caused by ongoing CSF leak from the dural puncture site, resulting in low CSF pressure and compensatory cerebral vasodilation. Treatment includes flat positioning, oral fluid intake (2-3 L/day to promote CSF production), caffeine (oral or IV), and if persistent >24-48 hours, an autologous epidural blood patch." }]
  },

  "brain-death": {
    title: "Brain Death Determination",
    cellular: { title: "Irreversible Cessation of Brain Function", content: "Brain death is the irreversible cessation of all functions of the entire brain, including the brainstem. It is legally equivalent to death in most jurisdictions. Brain death occurs when devastating brain injury (massive stroke, severe TBI, prolonged anoxia) causes complete loss of cerebral and brainstem function. The determination requires specific prerequisites, clinical examination, and may require confirmatory testing. Prerequisites include: known cause of coma, exclusion of confounders (hypothermia <36°C, drug intoxication, metabolic derangements, neuromuscular blocking agents). Clinical examination demonstrates absence of brainstem reflexes and absence of respiratory drive (apnea test)." },
    riskFactors: ["Massive intracerebral hemorrhage", "Severe traumatic brain injury", "Prolonged cardiac arrest with anoxic brain injury", "Large ischemic stroke", "Fulminant meningitis/encephalitis"],
    diagnostics: ["Prerequisites confirmed: known cause, confounders excluded, core temp ≥36°C", "Coma: no eye opening or motor response to noxious central stimulation", "Absent brainstem reflexes: pupils fixed and dilated, no corneal reflex, no oculocephalic (doll's eyes), no oculovestibular (cold calorics), no gag, no cough", "Apnea test: no respiratory effort when PaCO2 rises to ≥60 mmHg (or 20 mmHg above baseline)", "Confirmatory tests (if needed): cerebral angiography, EEG, nuclear brain perfusion scan showing no flow"],
    management: ["Two physicians confirm brain death (policies vary by institution and jurisdiction)", "Family notification and support", "Consideration of organ donation - contact organ procurement organization", "Maintain physiologic support if organ donation being pursued", "Time of death is time of brain death pronouncement, not when ventilator is withdrawn"],
    nursingActions: ["Ensure all prerequisites are met before brain death examination", "Assist with brain death examination: assess brainstem reflexes systematically", "Monitor during apnea test: disconnect ventilator, provide passive oxygenation, check ABG for PaCO2", "Provide compassionate family support throughout the process", "Contact organ procurement organization per protocol", "Maintain physiologic support (ventilator, vasopressors, temperature management) if organ donation planned", "Document examination findings precisely", "Address staff emotional needs - brain death situations are emotionally difficult for nurses"],
    signs: { left: ["No response to noxious stimulation (no motor response, no eye opening)", "Pupils fixed and dilated bilaterally (no light reflex)", "No corneal reflex (no blink when cornea touched)", "No oculocephalic reflex (doll's eyes absent - eyes move with head turning)"], right: ["No oculovestibular reflex (no eye movement with cold water caloric testing)", "No gag or cough reflex (no response to suctioning or pharyngeal stimulation)", "No respiratory effort when PaCO2 ≥60 mmHg (failed apnea test)", "Spinal reflexes may persist (do NOT indicate brain function) - limb movements from spinal cord"] },
    medications: [{ name: "No Medication Applicable", type: "Clinical Determination", action: "Brain death is a clinical diagnosis. No medications are used for diagnosis. Medications that may confound the examination must be excluded or cleared before testing", sideEffects: "N/A", contra: "N/A", pearl: "Spinal reflexes (Lazarus sign, limb withdrawal) can occur AFTER brain death because the spinal cord may still function. These do NOT indicate brain activity and should be explained to families to prevent confusion." }],
    pearls: ["Brain death = legal death. Time of death is when brain death is pronounced, NOT when mechanical support is withdrawn", "Spinal reflexes (limb movements) can persist after brain death and are NOT signs of brain function - explain this to families", "The apnea test confirms absence of respiratory drive: the patient is disconnected from the ventilator, PaCO2 is allowed to rise to ≥60 mmHg, and no respiratory effort is observed", "Organ donation should be discussed with families after brain death - this is a separate conversation from the death pronouncement"],
    quiz: [{ question: "During brain death testing, the family observes the patient's arm move. They ask if this means the patient is alive. The nurse's best response is:", options: ["The patient may be recovering - we should stop the brain death exam", "These are spinal reflexes from the spinal cord and do NOT indicate brain function. The brain has no activity.", "This movement is involuntary and we should give more sedation", "We cannot determine brain death if the patient is moving"], correct: 1, rationale: "Spinal reflexes (including limb movements and the Lazarus sign) can persist after brain death because the spinal cord functions independently of the brain. These movements are NOT evidence of consciousness or brain function. Explaining this clearly and compassionately to families is an important nursing responsibility." }]
  },

  "diabetes-insipidus-neuro": {
    title: "Diabetes Insipidus (Neurogenic)",
    cellular: { title: "ADH Deficiency in Neurological Injury", content: "Central (neurogenic) diabetes insipidus occurs when the hypothalamus or posterior pituitary fails to produce or release adequate antidiuretic hormone (ADH/vasopressin). In neurological patients, this commonly results from TBI, neurosurgery (especially transsphenoidal pituitary surgery), brain death, or hemorrhagic stroke affecting the hypothalamic-pituitary axis. Without ADH, the collecting ducts of the kidneys cannot reabsorb water, resulting in massive diuresis of dilute urine (up to 20 liters per day). This leads to life-threatening dehydration and hypernatremia if not promptly treated with fluid replacement and desmopressin (synthetic ADH)." },
    riskFactors: ["Transsphenoidal pituitary surgery (most common surgical cause)", "Traumatic brain injury with hypothalamic-pituitary damage", "Brain death (posterior pituitary infarction)", "Craniopharyngioma or other sellar/suprasellar tumors", "Cerebral aneurysm surgery near the pituitary stalk"],
    diagnostics: ["Massive polyuria: urine output >250 mL/hr or >3 L in 24 hours", "Dilute urine: specific gravity <1.005, urine osmolality <200 mOsm/kg", "Elevated serum sodium (hypernatremia >145 mEq/L)", "Elevated serum osmolality (>295 mOsm/kg)", "Low urine osmolality with high serum osmolality confirms DI", "Water deprivation test differentiates central from nephrogenic DI"],
    management: ["Desmopressin (DDAVP) for central DI - replaces deficient ADH", "Aggressive IV fluid replacement matching urine output", "Monitor and correct hypernatremia gradually (no faster than 10-12 mEq/L per 24 hours)", "Strict intake and output monitoring", "Aqueous vasopressin IV drip for acute settings"],
    nursingActions: ["Monitor urine output hourly - report output >250 mL/hr", "Measure urine specific gravity each void", "Monitor serum sodium every 4-6 hours during acute phase", "Replace fluids as ordered: typically mL-for-mL replacement of urine output", "Administer DDAVP as prescribed: intranasal, IV, or subcutaneous", "Monitor for signs of dehydration: dry mucous membranes, poor skin turgor, tachycardia", "Monitor for rapid sodium correction (risk of cerebral edema)", "Strict intake and output with daily weights", "Ensure patient has access to water and is not NPO without IV fluid replacement"],
    signs: { left: ["Polyuria: massive urine output of dilute, pale, colorless urine", "Polydipsia: extreme thirst (if patient is conscious and able to drink)", "Dehydration: poor skin turgor, dry mucous membranes, tachycardia, hypotension", "Hypernatremia: confusion, irritability, seizures if severe"], right: ["Urine specific gravity <1.005 (very dilute)", "Serum sodium >145 mEq/L (rising)", "Serum osmolality elevated >295 mOsm/kg", "Weight loss from fluid loss"] },
    medications: [{ name: "Desmopressin (DDAVP)", type: "Synthetic ADH Analog", action: "Binds V2 receptors in the renal collecting duct, stimulating aquaporin-2 insertion and water reabsorption, concentrating the urine and correcting polyuria and hypernatremia", sideEffects: "Hyponatremia (overcorrection), water intoxication, headache, nausea", contra: "Type IIB von Willebrand disease, hyponatremia", pearl: "Available as intranasal spray, IV, or subcutaneous injection. After transsphenoidal surgery, DI may be transient (resolves in days), permanent, or triphasic (DI → SIADH → permanent DI). Monitor sodium closely through all phases." }],
    pearls: ["DI after transsphenoidal pituitary surgery may follow a triphasic pattern: DI (days 1-3) → SIADH (days 4-10) → permanent DI if stalk damaged", "Central DI responds to DDAVP (synthetic ADH); nephrogenic DI does NOT (kidneys cannot respond to ADH)", "In brain death, DI occurs because the posterior pituitary infarcts - massive polyuria is a common finding", "Correct hypernatremia gradually - rapid correction risks cerebral edema. Target no more than 10-12 mEq/L decrease in sodium per 24 hours"],
    quiz: [{ question: "A patient 12 hours post-transsphenoidal pituitary surgery has urine output of 400 mL/hr for the past 3 hours. Urine specific gravity is 1.002. Serum sodium is 152 mEq/L. What does the nurse suspect?", options: ["Normal post-operative diuresis", "SIADH", "Central diabetes insipidus", "Nephrogenic diabetes insipidus"], correct: 2, rationale: "Massive polyuria (400 mL/hr) with dilute urine (specific gravity 1.002) and hypernatremia (152) after pituitary surgery is classic central diabetes insipidus from disruption of ADH production or release. SIADH would cause oliguria with concentrated urine and hyponatremia - the opposite picture." }]
  },

  "siadh-neuro": {
    title: "SIADH in Neurological Conditions",
    cellular: { title: "Excessive ADH Secretion", content: "The syndrome of inappropriate antidiuretic hormone (SIADH) occurs when excessive ADH is released despite normal or low serum osmolality, causing the kidneys to retain water inappropriately. In neurological conditions, SIADH commonly results from brain tumors, meningitis, encephalitis, SAH, TBI, and post-neurosurgical states. Excessive water retention causes dilutional hyponatremia (serum sodium <135 mEq/L) and decreased serum osmolality, while urine becomes concentrated. Severe hyponatremia (<120 mEq/L) can cause cerebral edema, seizures, coma, and death. The hallmark is euvolemic hyponatremia with concentrated urine." },
    riskFactors: ["Subarachnoid hemorrhage", "TBI and neurosurgery", "Brain tumors (especially pituitary)", "CNS infections: meningitis, encephalitis", "Medications: SSRIs, carbamazepine, NSAIDs, cyclophosphamide", "Post-transsphenoidal surgery (part of triphasic response)"],
    diagnostics: ["Hyponatremia: serum sodium <135 mEq/L", "Low serum osmolality (<275 mOsm/kg)", "Concentrated urine: urine osmolality >100 mOsm/kg, urine sodium >40 mEq/L", "Euvolemia: no signs of dehydration or fluid overload", "Must rule out hypothyroidism and adrenal insufficiency before diagnosing SIADH"],
    management: ["Fluid restriction: 800-1200 mL/day (primary treatment)", "Hypertonic saline (3% NaCl) for severe symptomatic hyponatremia (seizures, coma)", "Correct sodium gradually: no more than 8-10 mEq/L per 24 hours to prevent osmotic demyelination syndrome", "Vasopressin receptor antagonists (conivaptan, tolvaptan) for refractory SIADH", "Treat underlying cause"],
    nursingActions: ["Implement and monitor fluid restriction strictly", "Monitor serum sodium every 4-6 hours during correction", "Report sodium correction rate - do NOT exceed 8-10 mEq/L per 24 hours", "Monitor for neurological symptoms of hyponatremia: confusion, headache, nausea, seizures", "Weigh patient daily - weight gain indicates water retention", "Monitor I&O strictly", "Educate patient and family about fluid restriction rationale", "Administer hypertonic saline via central line only with infusion pump", "Monitor for osmotic demyelination syndrome: dysarthria, dysphagia, quadriparesis (if sodium corrected too rapidly)"],
    signs: { left: ["Hyponatremia: confusion, headache, nausea, lethargy", "Severe hyponatremia (<120): seizures, coma, respiratory arrest", "Weight gain without edema (euvolemic state)", "Decreased urine output of concentrated urine"], right: ["Low serum osmolality with inappropriately concentrated urine", "Serum sodium <135 mEq/L (may be much lower)", "Urine sodium >40 mEq/L", "No signs of dehydration or fluid overload (euvolemic)"] },
    medications: [{ name: "3% Hypertonic Saline", type: "Concentrated Sodium Chloride Solution", action: "Raises serum sodium concentration by providing concentrated sodium to treat symptomatic severe hyponatremia, drawing water out of cerebral cells by osmotic gradient to reduce cerebral edema", sideEffects: "Central pontine myelinolysis (osmotic demyelination) if corrected too rapidly, fluid overload, phlebitis", contra: "Correction rate must not exceed 8-10 mEq/L per 24 hours. Must be given via central line", pearl: "ONLY used for SYMPTOMATIC severe hyponatremia (seizures, altered consciousness). Administer via infusion pump through a central line. Monitor sodium every 2 hours during infusion. STOP immediately if sodium correction rate approaches limit. Osmotic demyelination syndrome from over-correction is DEVASTATING and irreversible." }],
    pearls: ["SIADH = dilutional hyponatremia from water RETENTION (too much ADH holds water). DI = hypernatremia from water LOSS (too little ADH loses water). They are OPPOSITES", "Correct hyponatremia SLOWLY: no more than 8-10 mEq/L per 24 hours. Rapid correction causes osmotic demyelination syndrome (central pontine myelinolysis) - irreversible brainstem damage", "SIADH is EUVOLEMIC hyponatremia - the patient does not appear dehydrated or fluid overloaded", "The primary treatment for SIADH is FLUID RESTRICTION - this seems counterintuitive to patients, so education is important"],
    quiz: [{ question: "A patient with SIADH has a serum sodium of 118 mEq/L and is having seizures. The physician orders 3% hypertonic saline. What is the nurse's most important monitoring parameter?", options: ["Blood pressure every 15 minutes", "Urine output every hour", "Serum sodium every 2 hours to ensure correction rate does not exceed 8-10 mEq/L per 24 hours", "Temperature every 4 hours"], correct: 2, rationale: "The most critical monitoring parameter is the rate of sodium correction. Correcting hyponatremia too rapidly (>8-10 mEq/L per 24 hours) causes osmotic demyelination syndrome (central pontine myelinolysis), which is irreversible and devastating. Serum sodium must be checked every 2 hours during hypertonic saline infusion, and the infusion stopped if the correction rate approaches the limit." }]
  },

  "cerebral-perfusion-pressure": {
    title: "Cerebral Perfusion Pressure Management",
    cellular: { title: "CPP Optimization in Neurological Injury", content: "Cerebral perfusion pressure (CPP) is the net pressure gradient driving blood flow to the brain, calculated as CPP = MAP - ICP. Normal CPP is 60-100 mmHg. CPP below 60 mmHg leads to cerebral ischemia, while CPP above 70 mmHg may cause vasogenic edema and ARDS from aggressive vasopressor use. Brain Trauma Foundation guidelines recommend maintaining CPP between 60-70 mmHg in severe TBI. CPP can be optimized by two strategies: reducing ICP (osmotic therapy, CSF drainage, surgical decompression) or increasing MAP (vasopressors, volume resuscitation). Autoregulation (the brain's ability to maintain constant blood flow despite BP changes) is often impaired after brain injury, making CPP management critical." },
    riskFactors: ["Severe TBI (GCS ≤8)", "Large stroke with cerebral edema", "SAH with vasospasm", "Brain tumor with mass effect", "Hepatic encephalopathy", "Any condition causing elevated ICP"],
    diagnostics: ["ICP monitoring: intraventricular catheter (EVD) or intraparenchymal sensor", "Continuous MAP monitoring via arterial line", "CPP calculation: MAP - ICP", "Brain tissue oxygen monitoring (PbtO2) in select centers", "Jugular venous oxygen saturation (SjvO2) as indicator of cerebral metabolic supply-demand balance"],
    management: ["Target CPP 60-70 mmHg (Brain Trauma Foundation guidelines for TBI)", "Reduce ICP if elevated: osmotic therapy, CSF drainage, sedation, decompressive craniectomy", "Increase MAP if needed: IV vasopressors (norepinephrine), IV fluids", "Avoid CPP >70 mmHg (risk of ARDS from aggressive vasopressor use)", "Maintain euvolemia - neither hypovolemia nor hypervolemia"],
    nursingActions: ["Monitor ICP and MAP continuously, calculate CPP and trend hourly", "Report CPP <60 mmHg or >70 mmHg immediately", "Zero the ICP monitor at the tragus of the ear (foramen of Monro)", "Ensure arterial line is transduced at the level of the phlebostatic axis", "Titrate vasopressors to maintain target CPP as ordered", "Manage ICP with HOB 30°, head midline, avoid Valsalva, cluster care", "Document ICP, MAP, CPP, and interventions hourly", "Report ICP waveform changes: P2 > P1 indicates decreased compliance"],
    signs: { left: ["CPP <60: cerebral ischemia - declining GCS, pupil changes, worsening deficits", "CPP >70: risk of pulmonary edema from aggressive vasopressor use", "Rising ICP with constant MAP: CPP decreases, ischemia risk increases", "Loss of ICP waveform: catheter malfunction, occlusion, or brain herniation"], right: ["ICP waveform: P1 (percussion wave), P2 (tidal wave), P3 (dicrotic wave)", "P2 > P1 (abnormal): indicates decreased intracranial compliance", "Lundberg A waves (plateau waves): sustained ICP elevation 50-100 mmHg for 5-20 minutes - EMERGENCY", "Lundberg B waves: rhythmic ICP oscillations indicating impaired compliance"] },
    medications: [{ name: "Norepinephrine", type: "Vasopressor", action: "Alpha-1 and beta-1 agonist that increases MAP through vasoconstriction and increased cardiac output, thereby increasing CPP when ICP management alone is insufficient", sideEffects: "Peripheral ischemia, arrhythmias, tissue necrosis with extravasation", contra: "Must be administered through central venous access, not peripheral IV", pearl: "When CPP is low due to low MAP (not just high ICP), vasopressors may be needed. However, targeting CPP >70 increases risk of ARDS from lung injury. The optimal CPP target in TBI is 60-70 mmHg." }],
    pearls: ["CPP = MAP - ICP. Both high ICP and low MAP decrease CPP, causing cerebral ischemia", "Target CPP 60-70 mmHg in TBI. Too low = ischemia, too high = ARDS risk from vasopressors", "ICP waveform analysis: P2 greater than P1 indicates decreased intracranial compliance and risk of sudden ICP spikes", "Zero the ICP transducer at the tragus of the ear (approximates the foramen of Monro/lateral ventricle level) for accurate readings"],
    quiz: [{ question: "A patient's ICP is 22 mmHg and MAP is 75 mmHg. What is the CPP and what action is needed?", options: ["CPP 53 - below target, increase MAP or decrease ICP", "CPP 97 - above target, decrease vasopressors", "CPP 75 - within target, no action needed", "CPP 22 - critically low, emergent intervention"], correct: 0, rationale: "CPP = MAP - ICP = 75 - 22 = 53 mmHg. Target CPP is 60-70 mmHg, so 53 is below target. Interventions include reducing ICP (mannitol, hypertonic saline, CSF drainage) and/or increasing MAP (vasopressors, volume resuscitation) to achieve target CPP." }]
  },

  "neuropathic-pain": {
    title: "Neuropathic Pain Management",
    cellular: { title: "Pathological Pain Processing", content: "Neuropathic pain results from damage or dysfunction of the somatosensory nervous system (peripheral nerves, dorsal root ganglia, spinal cord, or brain). Unlike nociceptive pain from tissue damage, neuropathic pain persists beyond tissue healing and involves pathological changes in pain processing: peripheral sensitization (lowered firing thresholds in damaged nerve fibers), central sensitization (amplified pain signaling in the spinal cord dorsal horn), and loss of descending inhibitory modulation. Patients describe burning, shooting, electric-shock, or pins-and-needles sensations. Allodynia (pain from normally non-painful stimuli) and hyperalgesia (exaggerated pain from painful stimuli) are hallmarks. Traditional analgesics (NSAIDs, opioids) are less effective for neuropathic pain; first-line treatments target the altered neural pathways." },
    riskFactors: ["Diabetic peripheral neuropathy", "Post-herpetic neuralgia (after shingles)", "Spinal cord injury", "Multiple sclerosis", "Stroke (central post-stroke pain)", "Phantom limb pain after amputation", "Chemotherapy-induced neuropathy", "Trigeminal neuralgia", "Complex regional pain syndrome"],
    diagnostics: ["Pain quality descriptors: burning, shooting, electric, tingling (distinguish from nociceptive pain)", "DN4 questionnaire or Leeds Assessment of Neuropathic Symptoms and Signs (LANSS)", "Sensory examination: allodynia, hyperalgesia, hypoesthesia, temperature sensitivity", "EMG/NCS for peripheral neuropathy characterization", "MRI for central neuropathic pain etiology"],
    management: ["First-line: gabapentin or pregabalin (calcium channel alpha-2-delta ligands)", "First-line: duloxetine or venlafaxine (SNRIs) for diabetic neuropathy, fibromyalgia", "First-line: tricyclic antidepressants (amitriptyline, nortriptyline) for post-herpetic neuralgia", "Topical lidocaine 5% patch for localized neuropathic pain", "Carbamazepine for trigeminal neuralgia (first-line for this specific condition)", "Opioids: second or third-line due to modest efficacy and risks in chronic neuropathic pain"],
    nursingActions: ["Assess pain quality using neuropathic pain descriptors (burning, shooting, electric)", "Differentiate neuropathic from nociceptive pain to guide treatment", "Educate that neuropathic pain medications take 2-4 weeks for full effect", "Monitor for medication side effects: sedation (gabapentin), nausea (duloxetine), cardiac effects (TCAs)", "Teach non-pharmacologic adjuncts: TENS, relaxation, CBT, physical therapy", "Avoid touching or applying pressure to allodynic areas", "Use validated neuropathic pain scales for assessment and monitoring"],
    signs: { left: ["Burning, shooting, or electric shock-like pain", "Allodynia: pain from light touch, clothing contact, or temperature changes", "Hyperalgesia: exaggerated pain response to mildly painful stimuli", "Paresthesias: spontaneous tingling, pins-and-needles sensation"], right: ["Pain in a neuroanatomical distribution (dermatomal, peripheral nerve, central)", "Hypoesthesia: decreased sensation in the painful area (paradoxical)", "Dysesthesia: unpleasant abnormal sensation", "Pain unresponsive to traditional analgesics (NSAIDs, acetaminophen)"] },
    medications: [{ name: "Gabapentin", type: "Anticonvulsant/Neuropathic Pain Agent", action: "Binds alpha-2-delta subunit of voltage-gated calcium channels, reducing release of excitatory neurotransmitters (glutamate, substance P, norepinephrine) from hyperexcitable nociceptive neurons", sideEffects: "Dizziness, somnolence, peripheral edema, weight gain, ataxia", contra: "Dose adjustment in renal impairment. Must taper gradually to discontinue (seizure risk with abrupt cessation)", pearl: "Start low (100-300mg at bedtime) and titrate slowly over weeks. Effective dose range is 900-3600mg/day in divided doses. Full effect may take 2-4 weeks. More effective for burning and tingling pain than for shooting/electric pain." }],
    pearls: ["Neuropathic pain does NOT respond well to traditional analgesics (NSAIDs, acetaminophen) - it requires medications that target altered neural pathways (gabapentinoids, SNRIs, TCAs)", "Carbamazepine is specifically first-line for trigeminal neuralgia - it is NOT the first choice for other neuropathic pain conditions", "Neuropathic pain medications take 2-4 WEEKS for full therapeutic effect - educate patients about this timeline to prevent premature discontinuation", "Allodynia (pain from non-painful stimuli like clothing touch) is a hallmark feature that helps identify neuropathic pain"],
    quiz: [{ question: "A patient with diabetic neuropathy describes burning, tingling pain in both feet that is not relieved by ibuprofen. Which medication class is most appropriate as first-line treatment?", options: ["Higher-dose NSAIDs", "Opioid analgesics", "Gabapentinoids (gabapentin or pregabalin) or SNRIs (duloxetine)", "Corticosteroids"], correct: 2, rationale: "Neuropathic pain from diabetic peripheral neuropathy responds poorly to NSAIDs because the pain mechanism is neural (altered pain processing) rather than inflammatory. First-line treatments include gabapentinoids (gabapentin, pregabalin) and SNRIs (duloxetine), which target the altered calcium channel function and descending pain modulation pathways respectively." }]
  }
};
